import math

def calculate(expression):
    """
    A calculator function that supports basic arithmetic operations,
    advanced mathematical functions, and trigonometric functions.

    Args:
        expression (str): The mathematical expression to evaluate.

    Returns:
        float: The result of the expression.

    Raises:
        ValueError: If the expression is invalid or contains unsupported operations.
    """

    try:
        # Basic arithmetic operations
        expression = expression.replace("^", "**")  # Replace ^ with ** for exponentiation

        # Advanced mathematical functions
        if "sqrt" in expression:
            expression = expression.replace("sqrt", "math.sqrt")
        if "log" in expression:
            expression = expression.replace("log", "math.log")
        if "factorial" in expression:
            def factorial(n):
                if n == 0:
                    return 1
                else:
                    return n * factorial(n-1)
            expression = expression.replace("factorial(", "factorial_wrapper(")
            def factorial_wrapper(n):
                n = int(n)
                if n < 0:
                    raise ValueError("Factorial is not defined for negative numbers")
                return factorial(n)

        # Trigonometric functions (assuming radians)
        if "sin" in expression:
            expression = expression.replace("sin", "math.sin")
        if "cos" in expression:
            expression = expression.replace("cos", "math.cos")
        if "tan" in expression:
            expression = expression.replace("tan", "math.tan")
        if "asin" in expression:
            expression = expression.replace("asin", "math.asin")
        if "acos" in expression:
            expression = expression.replace("acos", "math.acos")
        if "atan" in expression:
            expression = expression.replace("atan", "math.atan")

        # Evaluate the expression using eval()
